// Obtener respuesta de la IA
const item = $input.item.json;
const aiResponse = item.output || item.text || item.response || (item.message ? item.message.content : '') || '';

let result = { ads: [], scripts: [] };

try {
    let cleanJson = aiResponse;

    // 1. Limpieza Agresiva de Markdown y Glitch de IA
    if (typeof cleanJson === 'string') {
        const firstBrace = cleanJson.indexOf('{');
        const lastBrace = cleanJson.lastIndexOf('}');

        if (firstBrace > -1 && lastBrace > -1) {
             cleanJson = cleanJson.substring(firstBrace, lastBrace + 1);
        } else {
             // Limpiar ```json o ``` si no encuentra llaves
             cleanJson = cleanJson.replace(/```json/gi, '').replace(/```/g, '').trim();
        }
    }

    // 2. Intentar Parsear
    const parsed = JSON.parse(cleanJson);

    result.ads = Array.isArray(parsed.ads) ? parsed.ads : [];
    result.scripts = Array.isArray(parsed.scripts) ? parsed.scripts : [];

    // 3. GENERAR IMÁGENES (Pollinations)
    result.ads = result.ads.map(ad => {
        if (ad.image_prompt) {
            const seed = Math.floor(Math.random() * 1000);
            const safePrompt = encodeURIComponent(ad.image_prompt.substring(0, 200));
            // URL Mágica de Pollinations (Flux)
            ad.generated_image_url = `https://image.pollinations.ai/prompt/${safePrompt}?width=1080&height=1080&model=flux&nologo=true&seed=${seed}`;
        }
        return ad;
    });

} catch (error) {
    // Si falla el parseo, devolvemos un objeto de error bonito
    result.ads = [{ 
        type: 'Error IA', 
        headline: 'Intenta de nuevo', 
        primary_text: 'La IA devolvió un formato inválido (' + error.message + '). Dale a Generar otra vez.',
        generated_image_url: 'https://placehold.co/600x600?text=Error+IA'
    }];
}

// 4. Recuperar datos del producto original
let scrapeData = { main_image: '', product_title: '' };
try {
    if ($('Extract & Normalize').first()) scrapeData = $('Extract & Normalize').first().json;
} catch(e) {}

return {
    ads: result.ads,
    scripts: result.scripts,
    product_image: scrapeData.main_image || '', 
    product_title: scrapeData.product_title || 'Producto'
};
